window.__QUIZ_DATA__=[{"id":"theory>Physics>1998>1>a","subject":"Physics","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"Explain the term uniform acceleration.","images":[],"marking_scheme":"Uniform acceleration is said to occur or a body is said to be moving with uniform acceleration when the rate of increase in velocity with time is constant. It is measured in ms-2. It is a vector quantity.","marks":"2","difficulty":"1"},{"id":"theory>Physics>1998>1>b>i","subject":"Physics","year":"1998","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"Sketch and describe the velocity-time graph for the motion of a ball from the time it is projected vertically upwards until it returns to the point of projection.","images":["data:image/png;base64,"],"marking_scheme":"The above sketch shows the v-t graph of the ball. The velocity decreases uniformly from A to zero (B) at the top of its flight in a time YB. It then increases in velocity uniformly as it returns to the point of projection A.","marks":"4","difficulty":"2"},{"id":"theory>Physics>1998>1>b>ii","subject":"Physics","year":"1998","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"RECTILINEAR ACCELERATION : MOTION UNDER GRAVITY","question":"Neglecting air resistance and using your sketch, explain how the acceleration of free fall due to gravity, g, and the maximum height attained when the ball is projected vertically upwards can be determined.","images":[],"marking_scheme":"The acceleration of a free fall (g) can be determined from the sketch by considering slope \"AB\" or A1B1. The height attained by the ball when projected is the total area of triangle AYB","marks":"4","difficulty":"3"},{"id":"theory>Physics>1998>1>c>i","subject":"Physics","year":"1998","type":"Theory","sub_label":"i","group":"FINAL","topic":"RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION","question":"A stone is projected vertically upwards with a velocity of 20 ms-1. Two seconds later, a second stone is similarly projected with the same velocity. When the two stones meet, the second one is rising at a velocity of 10 ms-1. Neglecting air resistance, calculate the:    length of time the second stone is in motion before they meet.    [Take g as 10 ms-2]","images":["data:image/png;base64,"],"marking_scheme":"u1 = 20 ms-1; u2 = 20 ms-1; t1 = 2 s; t2 = ?; v = 10 ms-1  When the second stone is projected upwards, its acceleration = +g; v = u - gt  \u21d2 10 = 20 - 10t  =  10t = 20 - 10  = 10t = 10  \u2234t=1010=1s  This shows that the second stone has been in air for 1 s before they met.","marks":"6","difficulty":"3"},{"id":"theory>Physics>1998>1>c>ii","subject":"Physics","year":"1998","type":"Theory","sub_label":"ii","group":"FINAL","topic":"RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION","question":"A stone is projected vertically upwards with a velocity of 20 ms-1. Two seconds later, a second stone is similarly projected with the same velocity. When the two stones meet, the second one is rising at a velocity of 10 ms-1. Neglecting air resistance, calculate the:  velocity of the first stone when they meet.    [Take g as 10 ms-2]","images":[],"marking_scheme":"The total time of the first stone in air = (1 + 2) = 3 s  The velocity = u - gt = 20 - (10 x 3) = 20 - 30 = -10 ms-1  The velocity is minus because its coming down","marks":"4","difficulty":"3"},{"id":"theory>Physics>1998>2>a","subject":"Physics","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"Distinguish between heat and temperature","images":[],"marking_scheme":"Heat is the total internal energy possessed by a body and it is measured in Joules while temperature is the degree of hotness or coldness of a body which is measured in oC or K.","marks":"2","difficulty":"1"},{"id":"theory>Physics>1998>2>b","subject":"Physics","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"State  two  physical properties of substances which may be used to measure temperature","images":[],"marking_scheme":"- The change in volume expansion of a fixed mass of a liquid  - The change in electrical resistance of a substance","marks":"2","difficulty":"1"},{"id":"theory>Physics>1998>2>c","subject":"Physics","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"State  two  reasons why mercury is preferred to alcohol as a thermometric liquid.","images":[],"marking_scheme":"- Mercury does not wet glass.  - Mercury boils at 357oC while alcohol boils at 78oC hence it cannot be used to measure a very high temperature.  - It is opaque in colour and therefore can be easily seen.","marks":"2","difficulty":"2"},{"id":"theory>Physics>1998>2>d>i","subject":"Physics","year":"1998","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"Describe how a mercury-in-glass thermometer is calibrated.","images":[],"marking_scheme":"Mercury in glass thermometer can be calibrated by supporting a thermometer vertically ensuring the bulb is covered with melting ice shavings. Allow the thread to fall until it remains in a position. Then mark this point as your lower fixed point. Again suspend this thermometer in a steam of hypsomers, allow the thread to rise until it remain constant, mark this point as upper fixed point. Divide the interval to a number of equal parts.","marks":"6","difficulty":"3"},{"id":"theory>Physics>1998>2>d>ii","subject":"Physics","year":"1998","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"State  two  precautions necessary to ensure an accurate result.","images":[],"marking_scheme":"- The thermometer bulb should not be placed inside the boiling water of the hypsometer.  - The mercury should be allowed for few minutes for the thread to be steady before making the thermometer","marks":"2","difficulty":"2"},{"id":"theory>Physics>1998>2>e","subject":"Physics","year":"1998","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Explain how land and sea breeze occur.","images":["data:image/png;base64,"],"marking_scheme":"In the day the land is hotter than sea because water has the greater specific heat capacity to that of land. Hence, low pressure is created on the land and cooler air from the sea blows to the land and this is termed sea breeze. Conversely, in the night the sea becomes warmer, the land can easily lose its heat therefore it is cooler than at sea. A low pressure is also created on the sea and cooler air from the land blows to the sea and this is termed land breeze.","marks":"6","difficulty":"2"},{"id":"theory>Physics>1998>3>a>i","subject":"Physics","year":"1998","type":"Theory","sub_label":"i","group":"","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Describe, with the aid of a circuit diagram, an experiment to measure the resistance of a wire given an ammeter of low resistance, a battery, a key, a rheostat, a high-resistance voltmeter and some connecting wires.","images":["data:image/png;base64,"],"marking_scheme":"The resistance of a wire can be measured using the circuit above.   Procedure:  When the key is closed, the rheostat R is made in such a way that little current is flowing. The deflection/reading of the ammeter A as well as voltmeter V is taken. This experiment is repeated by changing the position of the rheostat and the readings of ammeter and voltmeter are recorded. The graph of V against I is a straight line passing through the origin is obtained, thus the slope of the graph is obtained which is equivalent to the resistance i.e. V/I = R. Hence R is determined.","marks":"6","difficulty":"3"},{"id":"theory>Physics>1998>3>a>ii","subject":"Physics","year":"1998","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"State  two  precautions necessary to obtain an accurate result.","images":[],"marking_scheme":"- A low current should be used.  - Error of parallax should be avoided when taking the readings from the ammeter and voltmeter.  - Zero error should be avoided.","marks":"2","difficulty":"2"},{"id":"theory>Physics>1998>3>b","subject":"Physics","year":"1998","type":"Theory","sub_label":"b","group":"","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"Using the experimental result and any necessary measurements, explain how the resistivity of the wire may be determined.","images":[],"marking_scheme":"Todetermineresistivityusingmethoddescribedin3(a)(i)  \u21d2SinceR=LA\u2234R=kLAwherekisconstant=resistivity  k=RAL;Risobtainedasslope;A=area,canbeobtainedbymeasuringthediameter  andusedittofindtheareaofthewirei.e.d2=r   A=\u03c0r2.ThenLisobtainedbymeasuringthewirebymetrerule  \u21d2k=RAL","marks":"4","difficulty":"3"},{"id":"theory>Physics>1998>3>c>i","subject":"Physics","year":"1998","type":"Theory","sub_label":"i","group":"","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"Two cells, each of e.m.f 2 V and internal resistance 0.5 \u03a9 are connected in series. They are made to supply current to a combination of three resistors, one of resistance 2 \u03a9 connected in series to a parallel combination of two other resistors each of resistance 3 \u03a9.  Draw the circuit diagram and calculate the:    current in the circuit","images":["data:image/png;base64,"],"marking_scheme":"Sinceit'saseriesconnection,Totale.m.f=2+2=4V  Totalr=0.5+0.5=1.0\u03a9  1R=13+13=23  \u2234R=32\u03a9  RT=2+32=72=3.5\u03a9  E=I(R+r)==>I=ER + r=43.5 + 1=44.5=89A","marks":"4","difficulty":"3"},{"id":"theory>Physics>1998>3>c>ii","subject":"Physics","year":"1998","type":"Theory","sub_label":"ii","group":"FINAL","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Two cells, each of e.m.f 2 V and internal resistance 0.5 \u03a9 are connected in series. They are made to supply current to a combination of three resistors, one of resistance 2 \u03a9 connected in series to a parallel combination of two other resistors each of resistance 3 \u03a9.  Draw the circuit diagram and calculate the:   potential difference across the parallel combination of the resistors","images":[],"marking_scheme":"P.d=IR=89x32=43V","marks":"2","difficulty":"3"},{"id":"theory>Physics>1998>3>c>iii","subject":"Physics","year":"1998","type":"Theory","sub_label":"iii","group":"FINAL","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Two cells, each of e.m.f 2 V and internal resistance 0.5 \u03a9 are connected in series. They are made to supply current to a combination of three resistors, one of resistance 2 \u03a9 connected in series to a parallel combination of two other resistors each of resistance 3 \u03a9.  Draw the circuit diagram and calculate the:   lost volts of the battery","images":[],"marking_scheme":"lostvoltageofthebattery=Ir=89x1=89v","marks":"2","difficulty":"3"},{"id":"theory>Physics>1998>4>a","subject":"Physics","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"Explain the term photoelectric effect","images":[],"marking_scheme":"When a metal plate is illuminated by light, electrons are emitted from the surface. This is termed photoelectric effect.","marks":"2","difficulty":"1"},{"id":"theory>Physics>1998>4>b>i","subject":"Physics","year":"1998","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents a photocell with its associated electric circuit. Identify each of the physical quantities represented by the letter A    - A","images":["data:image/png;base64,"],"marking_scheme":"Incident light","marks":"0.3","difficulty":"2"},{"id":"theory>Physics>1998>4>b>ii","subject":"Physics","year":"1998","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents a photocell with its associated electric circuit. Identify each of the physical quantities represented by the letter A - B","images":["data:image/png;base64,"],"marking_scheme":"- Cathode","marks":"0.33","difficulty":"2"},{"id":"theory>Physics>1998>4>b>iii","subject":"Physics","year":"1998","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents a photocell with its associated electric circuit. Identify each of the physical quantities represented by the letter A - C","images":["data:image/png;base64,"],"marking_scheme":"- Photo electron","marks":"0.33","difficulty":"2"},{"id":"theory>Physics>1998>4>b>iv","subject":"Physics","year":"1998","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents a photocell with its associated electric circuit. Identify each of the physical quantities represented by the letter A - D","images":["data:image/png;base64,"],"marking_scheme":"- Anode","marks":"0.33","difficulty":"2"},{"id":"theory>Physics>1998>4>b>v","subject":"Physics","year":"1998","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents a photocell with its associated electric circuit. Identify each of the physical quantities represented by the letter A - E","images":["data:image/png;base64,"],"marking_scheme":"- Vacuum","marks":"0.33","difficulty":"2"},{"id":"theory>Physics>1998>4>b>vi","subject":"Physics","year":"1998","type":"Theory","sub_label":"vi","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents a photocell with its associated electric circuit. Identify each of the physical quantities represented by the letter A - F","images":["data:image/png;base64,"],"marking_scheme":"- Glass tube","marks":"0.33","difficulty":"2"},{"id":"theory>Physics>1998>4>c>i","subject":"Physics","year":"1998","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"What factor determines the:    maximum current produced by the photocell","images":[],"marking_scheme":"Intensity of light","marks":"2","difficulty":"1"},{"id":"theory>Physics>1998>4>c>ii","subject":"Physics","year":"1998","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"What factor determines the:  maximum kinetic energy of the photo electrons?","images":[],"marking_scheme":"The kinetic energy of emitted electrons depend on the frequency of incident photons.","marks":"2","difficulty":"2"},{"id":"theory>Physics>1998>4>d","subject":"Physics","year":"1998","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"State  one  similarity and  one  difference between photoemission and evaporation","images":[],"marking_scheme":"Similarities:   - In both, emission occurs  - The particles are emitted at the surface       Differences:   - During evaporation, cooling occur while heat is produced during photo electric emission.  - In evaporation, \"molecules\" are involved while it is not during photoemission instead \"electron\" is emitted","marks":"2","difficulty":"2"},{"id":"theory>Physics>1998>4>e","subject":"Physics","year":"1998","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : THERMIONIC EMISSION","question":"Name  two  methods by which a beam of free electrons may be produced other than photoemission","images":[],"marking_scheme":"- Ionization of gases  - Thermionic emission","marks":"2","difficulty":"2"},{"id":"theory>Physics>1998>4>f","subject":"Physics","year":"1998","type":"Theory","sub_label":"f","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"State  two  applications to photoelectric effect.","images":[],"marking_scheme":"- Automatic devices  - Television cameras","marks":"2","difficulty":"1"},{"id":"theory>Physics>1998>4>g>i","subject":"Physics","year":"1998","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"A light of wavelength 5.0 x 10-7 m is incident on a metal resulting in photoemission of electrons. If the work function of the metal is 3.04 x 10-19 J, calculate the:    frequency of the light    [Speed of light = 3.0 x 108 ms-1]  [Planck's constant = 6.6 x 10-34 Js]","images":[],"marking_scheme":"\u03bb = 5.0 x 10-7 m; Wo =  3.04 x 10-19 J; c = 3.0 x 108 ms-1; h = 6.6 x 10-34 Js; f =?; E = ?  Sincec=f\u03bb==>f=c\u03bb=3.0 x 1085.0 x 10-7=6x1014Hz","marks":"2","difficulty":"3"},{"id":"theory>Physics>1998>4>g>ii","subject":"Physics","year":"1998","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"A light of wavelength 5.0 x 10-7 m is incident on a metal resulting in photoemission of electrons. If the work function of the metal is 3.04 x 10-19 J, calculate the:  energy of the incident photon.    [Speed of light = 3.0 x 108 ms-1]  [Planck's constant = 6.6 x 10-34 Js]","images":[],"marking_scheme":"E = hf = 6.6 x 10-34 x 6 x 1014 = 3.96 x 10-19 J","marks":"2","difficulty":"3"},{"id":"theory>Physics>1998>4>g>iii","subject":"Physics","year":"1998","type":"Theory","sub_label":"iii","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"A light of wavelength 5.0 x 10-7 m is incident on a metal resulting in photoemission of electrons. If the work function of the metal is 3.04 x 10-19 J, calculate the:  maximum kinetic energy of the photoelectrons.    [Speed of light = 3.0 x 108 ms-1]  [Planck's constant = 6.6 x 10-34 Js]","images":[],"marking_scheme":"Emax = E - Wo = 3.96 x 10-19 - 3.04 x 10-19 = 0.92 x 10-19 J = 9.2 x 10-20 J","marks":"2","difficulty":"3"}];